#include<cstdio>
#include<cstring>
#include<iostream>
#define rep(a,b,c) for(int c=(a);c<=(b);++c)
#define drep(a,b,c) for(int c=(a);c>=(b);--c)
using namespace std; 
inline int read()
{
	int res=0;char ch=getchar();bool flag=0;
	while(ch<'0'||ch>'9')flag^=(ch=='-'),ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();
	return flag ? -res : res ;
}
struct Matrix
{
	int a[610][610],n;
	inline Matrix(int N=0,bool x=0){n=N;memset(a,0,sizeof(a));if(x)rep(1,n,i)a[i][i]=1;}
	inline int Det(const int Mod)
	{
		bool flag=0;int res=1;rep(1,n,i)
		{
			register int k=0,mn=0x3f3f3f3f;
			rep(i,n,j)(a[j][i]?((a[j][i]<mn)?k=j,mn=a[j][i]:0):0);
			if(!k)return 0;if(i^k)swap(a[i],a[k]),flag^=1;
			rep(i+1,n,j)
			{
				a[j][i]>a[i][i]?(swap(a[j],a[i]),flag^=1):0;
				while(a[j][i])
				{
					register int tmp=a[i][i]/a[j][i];
					rep(i,n,k)a[i][k]=(a[i][k]+1ll*(Mod-tmp)*a[j][k])%Mod;
					swap(a[j],a[i]);flag^=1;
				}
			}
			res=1ll*res*a[i][i]%Mod;
		}
		return flag?(Mod-res)%Mod:res;
	}
}q;
int main()
{
	int n=q.n=read(),Mod=read();
	rep(1,n,i)rep(1,n,j)q.a[i][j]=read();
	printf("%d\n",(1ll*q.Det(Mod)+Mod)%Mod);
}
